args.sparql:
SELECT ?raceLabel WHERE {
  wd:Q17015440 p:P710 ?participant.
  ?participant ps:P710 wd:Q5755348;
               pq:P1923 ?jockey.
  ?race p:P710 ?winParticipant.
  ?winParticipant ps:P710 ?horse;
                  pq:P4724 1;
                  pq:P1923 ?jockey.
  ?horse wdt:P127 wd:Q1586488.
  ?race rdfs:label ?raceLabel.
  FILTER (LANG(?raceLabel) = "en")
}

SELECT ?race ?raceLabel
WHERE {
  wd:Q17015440 p:P710 ?participant.
  ?participant ps:P710 wd:Q5755348;
               pq:P1923 ?jockey.

  ?race p:P710 ?winParticipant.
  ?winParticipant ps:P710 ?horse;
                  pq:P4724 "1";
                  pq:P1923 ?jockey.
  ?horse wdt:P184 wd:Q1586488.

  ?race rdfs:label ?raceLabel.
  FILTER (LANG(?raceLabel) = "en")
  FILTER (?race != wd:Q17015440)
}

SELECT ?race ?raceLabel WHERE {
  wd:Q17015440 p:P710 ?preaknessPart.
  ?preaknessPart ps:P710 wd:Q5755348;
                 pq:P1923 ?jockey.

  ?race p:P710 ?otherPart.
  ?otherPart ps:P710 wd:Q5755348;
             pq:P1923 ?jockey;
             pq:P4724 1.

  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
  FILTER(?race != wd:Q17015440)
  FILTER(CONTAINS(?raceLabel, "Belmont") || CONTAINS(?raceLabel, "Derby"))
}

SELECT ?race ?raceLabel WHERE {
  wd:Q5755348 wdt:P127 wd:Q1586488.
  ?race p:P710 ?part.
  ?part ps:P710 wd:Q5755348;
        pq:P4724 1.
  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
}

SELECT ?race ?raceLabel WHERE {
  wd:Q17015440 p:P710 ?preaknessPart.
  ?preaknessPart ps:P710 wd:Q5755348;
                 pq:P1923 ?jockey.

  ?race p:P710 ?winPart.
  ?winPart ps:P710 ?horse;
          pq:P1923 ?jockey;
          pq:P4724 wd:Q21471069.
  ?horse wdt:P127 wd:Q1586488.

  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
}
LIMIT 1

SELECT ?race ?raceLabel WHERE {
  wd:Q17015440 p:P710 ?preaknessPart.
  ?preaknessPart ps:P710 wd:Q5755348;
                 pq:P1923 ?jockey.

  ?race p:P710 ?winPart.
  ?winPart ps:P710 ?horse;
          pq:P1923 ?jockey;
          pq:P4724 wd:Q1985420. # 1st place item
  ?horse wdt:P127 wd:Q1586488.

  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
  FILTER (?race != wd:Q17015440)
}
LIMIT 1

SELECT ?race ?raceLabel WHERE {
  wd:Q17015440 p:P710 ?preaknessPart.
  ?preaknessPart ps:P710 wd:Q5755348;
                 pq:P1923 ?jockey.

  ?race p:P710 ?winnerPart.
  ?winnerPart ps:P710 wd:Q5755348;
              pq:P1923 ?jockey;
              pq:P4724 "1".

  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
}
ORDER BY DESC(?raceLabel)
LIMIT 1

SELECT ?race ?raceLabel WHERE {
  wd:Q5755348 wdt:P127 wd:Q1586488.
  ?race p:P710 ?part.
  ?part ps:P710 wd:Q5755348;
        pq:P4724 "1".
  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
  FILTER(CONTAINS(?raceLabel, "Belmont"))
}

SELECT ?race ?raceLabel WHERE {
  wd:Q17015440 p:P710 ?preaknessPart.
  ?preaknessPart ps:P710 wd:Q5755348;
                 pq:P1923 ?jockey;
                 pq:P4724 ?position.

  ?race p:P710 ?winPart.
  ?winPart ps:P710 ?horse;
          pq:P1923 ?jockey;
          pq:P4724 wd:Q1985420.
  ?horse wdt:P127 wd:Q1586488.

  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
  FILTER(CONTAINS(?raceLabel, "Belmont"))
}

SELECT ?race (SAMPLE(?raceLabel) AS ?raceLabel) WHERE {
  wd:Q17015440 p:P710 ?preaknessPart.
  ?preaknessPart ps:P710 wd:Q5755348;
                 pq:P1923 ?jockey.

  ?race p:P710 ?winPart.
  ?winPart ps:P710 wd:Q5755348;
          pq:P1923 ?jockey;
          pq:P4724 "1".

  ?race rdfs:label ?raceLabel.
  FILTER(LANG(?raceLabel) = "en")
  FILTER(CONTAINS(?raceLabel, "Gold Cup"))
}
GROUP BY ?race
LIMIT 1
